  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_fc_main, vUv ).xyz;

    // motion blur by Geiss
    // 'v' points exactly one pixel, in the direction of motion
